import xml.etree.ElementTree as ET

def validate_xml_file(file_path):
    try:
        # Parse the XML file
        tree = ET.parse(file_path)
        root = tree.getroot()
        
        # Validate XML structure (example validation logic)
        if root.tag != 'Document':
            raise ValueError("Root element must be 'Document'")
        
        for child in root:
            if child.tag not in ['Header', 'Body']:
                raise ValueError(f"Unexpected child element: {child.tag}")
        
        # If no exceptions are raised, the XML is valid
        return True
    
    except ET.ParseError as e:
        print(f"XML parsing error: {e}")
    except ValueError as ve:
        print(f"Validation error: {ve}")
    except Exception as ex:
        print(f"An error occurred: {ex}")
    
    return False

